import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Products from './pages/Products';
import Cart from './pages/Cart';
import Wishlist from './pages/Wishlist';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/products' element={<Products />} />
        <Route path='/cart' element={<Cart />} />
        <Route path='/wishlist' element={<Wishlist />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const linkStyle = ({ isActive }) => ({
    textDecoration: 'none',
    color: isActive ? '#7c3aed' : '#64748b',
    fontWeight: isActive ? 700 : 500
  });

  return (
    <nav style={{ borderBottom: '1px solid #e9d5ff', background: '#fff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0, color: '#7c3aed' }}>GlowCart</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={linkStyle}>Home</NavLink>
          <NavLink to='/products' style={linkStyle}>Products</NavLink>
          <NavLink to='/cart' style={linkStyle}>Cart</NavLink>
          <NavLink to='/wishlist' style={linkStyle}>Wishlist</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function ProductCard({ product }) {
  return (
    <div style={{ border: '1px solid #e9d5ff', borderRadius: '14px', padding: '16px', background: '#fff', boxShadow: '0 2px 8px rgba(124,58,237,0.05)' }}>
      <h3 style={{ marginTop: 0 }}>{product.name}</h3>
      <p style={{ color: '#6b7280', margin: '6px 0' }}>{product.brand}</p>
      <p style={{ color: '#6b7280', margin: '6px 0' }}>Category: {product.category}</p>
      <p style={{ fontWeight: 700 }}>${product.price}</p>
      <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
        <button style={{ padding: '10px 12px', border: 'none', borderRadius: '10px', background: '#7c3aed', color: '#fff' }}>Add to Cart</button>
        <button style={{ padding: '10px 12px', border: '1px solid #ddd6fe', borderRadius: '10px', background: '#f5f3ff', color: '#7c3aed' }}>Wishlist</button>
      </div>
    </div>
  );
}

import React from 'react';

export default function Home() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ background: '#faf5ff', border: '1px solid #e9d5ff', borderRadius: '18px', padding: '32px' }}>
        <h1 style={{ marginTop: 0 }}>Beauty picks curated for you</h1>
        <p style={{ maxWidth: '700px', color: '#6b7280' }}>
          Explore featured cosmetics, save products to your wishlist, and build your perfect beauty cart with ease.
        </p>
      </div>
    </div>
  );
}

import React from 'react';
import ProductCard from '../components/ProductCard';

const products = [
  { id: 1, name: 'Matte Lipstick', brand: 'GlowPro', category: 'Makeup', price: 14 },
  { id: 2, name: 'Vitamin C Serum', brand: 'SkinAura', category: 'Skincare', price: 22 },
  { id: 3, name: 'Rose Blush', brand: 'LunaBeauty', category: 'Makeup', price: 16 }
];

export default function Products() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Products</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '18px' }}>
        {products.map(product => <ProductCard key={product.id} product={product} />)}
      </div>
    </div>
  );
}

import React from 'react';

const cartItems = [
  { id: 1, name: 'Matte Lipstick', quantity: 1, price: 14 },
  { id: 2, name: 'Vitamin C Serum', quantity: 1, price: 22 }
];

export default function Cart() {
  const total = cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0);

  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Cart</h1>
      {cartItems.map(item => (
        <div key={item.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '14px 0', borderBottom: '1px solid #ede9fe' }}>
          <span>{item.name}</span>
          <span>${item.price}</span>
        </div>
      ))}
      <div style={{ marginTop: '18px', fontWeight: 700 }}>Total: ${total}</div>
    </div>
  );
}

import React from 'react';

const wishlist = [
  { id: 1, name: 'Rose Blush', brand: 'LunaBeauty' },
  { id: 2, name: 'Hydrating Mist', brand: 'SkinAura' }
];

export default function Wishlist() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Wishlist</h1>
      <div style={{ display: 'grid', gap: '14px' }}>
        {wishlist.map(item => (
          <div key={item.id} style={{ border: '1px solid #e9d5ff', borderRadius: '12px', padding: '16px', background: '#fff' }}>
            <strong>{item.name}</strong>
            <p style={{ margin: '6px 0 0 0', color: '#6b7280' }}>{item.brand}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/products')
def get_products():
    return jsonify({
        'products': [
            {'id': 1, 'name': 'Matte Lipstick', 'brand': 'GlowPro', 'category': 'Makeup', 'price': 14},
            {'id': 2, 'name': 'Vitamin C Serum', 'brand': 'SkinAura', 'category': 'Skincare', 'price': 22},
            {'id': 3, 'name': 'Rose Blush', 'brand': 'LunaBeauty', 'category': 'Makeup', 'price': 16}
        ]
    })

@app.route('/api/wishlist')
def get_wishlist():
    return jsonify({
        'wishlist_items': [
            {'id': 1, 'product_name': 'Rose Blush', 'brand': 'LunaBeauty'},
            {'id': 2, 'product_name': 'Hydrating Mist', 'brand': 'SkinAura'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
